impl DepsEngine {
    /// Create a new DepsEngine, discovering all applicable providers
    pub fn new(config: &Config) -> Result<Self> {
        let providers = Self::discover_providers(config)?;
        // Only require experimental when deps is actually configured
        if !providers.is_empty() {
            Settings::get().ensure_experimental("deps")?;
        }
        Ok(Self { providers })
    }

    /// Create an engine containing providers from every explicit monorepo config root.
    ///
    /// Provider IDs are qualified with their config root (for example,
    /// `//apps/api:uv`) so the same provider name can be used in multiple roots.
    pub fn new_monorepo(
        config: &Config,
        config_files: impl IntoIterator<Item = Arc<dyn ConfigFile>>,
    ) -> Result<Self> {
        let monorepo_root = config
            .monorepo_root()
            .ok_or_else(|| eyre::eyre!("no config file in scope sets monorepo_root = true"))?;
        let mut providers: Vec<Box<dyn DepsProvider>> = vec![];
        let mut seen_ids = HashSet::new();

        for cf in config_files {
            let Some(config_project_root) = cf.project_root() else {
                continue;
            };
            if !config_project_root.starts_with(&monorepo_root) {
                continue;
            }
            let Some(deps_config) = cf.deps_config() else {
                continue;
            };

            let config_root = cf.config_root();
            let relative_root = config_root
                .strip_prefix(&monorepo_root)
                .unwrap_or(&config_root)
                .to_string_lossy()
                .replace('\\', "/");
            let scope = if relative_root.is_empty() {
                "//".to_string()
            } else {
                format!("//{relative_root}")
            };

            for (id, provider_config) in &deps_config.providers {
                if deps_config.disable.contains(id) {
                    continue;
                }

                let scoped_id = format!("{scope}:{id}");
                if !seen_ids.insert(scoped_id.clone()) {
                    continue;
                }

                if let Some(provider) =
                    Self::build_provider(id, &config_root, provider_config.clone())
                    && provider.is_applicable()
                {
                    providers.push(Box::new(ScopedDepsProvider::new(
                        provider, scoped_id, &scope,
                    )));
                }
            }
        }

        if !providers.is_empty() {
            Settings::get().ensure_experimental("deps")?;
        }
        Ok(Self { providers })
    }

    /// Discover all applicable deps providers for the current project
    ///
    /// Each config file's deps providers are scoped to that config file's directory.
    /// For example, a `[deps.pnpm]` defined in the root `mise.toml` only applies when
    /// running from the root directory, not from subdirectories.
    fn discover_providers(config: &Config) -> Result<Vec<Box<dyn DepsProvider>>> {
        let project_root = config
            .project_root
            .clone()
            .unwrap_or_else(|| std::env::current_dir().unwrap_or_default());

        let mut providers: Vec<Box<dyn DepsProvider>> = vec![];
        let mut seen_ids: HashSet<String> = HashSet::new();
        let mut disabled: Vec<String> = vec![];
    pub async fn monorepo_union_tool_request_set(self: &Arc<Self>) -> Result<ToolRequestSet> {
        Ok(self.monorepo_union().await?.tool_request_set)
    }

    pub(crate) async fn monorepo_union(self: &Arc<Self>) -> Result<MonorepoUnion> {
        let idiomatic_filenames = load_idiomatic_filenames().await;
        let config_filenames = idiomatic_filenames
            .keys()
            .chain(DEFAULT_CONFIG_FILENAMES.iter())
            .cloned()
            .collect_vec();
        let roots = self.monorepo_config_root_dirs_with_filenames(&config_filenames)?;
        let mut config_files = self.config_files.clone();
        let mut base_config_files = self.config_files.clone();
        base_config_files.retain(|path, _| {
            is_global_config(path) || !roots.iter().any(|root| path.starts_with(root))
        });

        let mut union = ToolRequestSet::new();
        for root in roots {
            let root_paths = config_paths_in_dir_with_filenames(&root, &config_filenames);
            let mut root_config_files =
                load_config_files_from_paths(&root_paths, &idiomatic_filenames).await?;
            for (path, cf) in root_config_files.clone() {
                config_files.entry(path).or_insert(cf);
            }
            for (path, cf) in base_config_files.clone() {
                root_config_files.entry(path).or_insert(cf);
            }

            let root_trs = ToolRequestSetBuilder::new()
                .with_config_files(root_config_files)
                .without_runtime_args()
                .build(self)
                .await?;
            union.unknown_tools.extend(root_trs.unknown_tools.clone());
            for (_ba, requests, source) in root_trs.iter() {
                for request in requests {
                    let already_present = union.tools.get(request.ba()).is_some_and(|existing| {
                        existing.iter().any(|r| {
                            r.version() == request.version() && r.options() == request.options()
                        })
                    });
                    if !already_present {
                        union.add_version(request.clone(), source);
                    }
                }
            }
        }

        union.unknown_tools = union.unknown_tools.into_iter().unique().collect();
        let repo_urls = load_plugins(&config_files)?;
        Ok(MonorepoUnion {
            config_files,
            tool_request_set: union,
            repo_urls,
        })
    }

    pub async fn tasks(&self) -> Result<Arc<BTreeMap<String, Task>>> {
        self.tasks_with_context(None).await
    }
